import{_ as e,c as i,a as d,o as a}from"./app-CEcM0piI.js";const s={};function r(n,t){return a(),i("div",null,t[0]||(t[0]=[d(`<h3 id="边框" tabindex="-1"><a class="header-anchor" href="#边框"><span>边框</span></a></h3><table><thead><tr><th>属性</th><th>作用</th></tr></thead><tbody><tr><td>border-width</td><td>定义边框粗细，单位是px</td></tr><tr><td>border-style</td><td>边框的样式</td></tr><tr><td>border-color</td><td>边框颜色</td></tr><tr><td>边框的复合属性没有顺序</td><td></td></tr></tbody></table><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>border:1px solid red;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>单独设置四个方向的边框</strong></p><ul><li>border-top : 上边框</li><li>border-bottom : 下边框</li><li>border-left : 左边框</li><li>border-right : 右边框</li></ul><p>每个方向的边框本质上都是一个小三角,如果盒子内没有内容,并把不同方向的边框改成不同颜色即可显示出</p><h4 id="表格细线边框" tabindex="-1"><a class="header-anchor" href="#表格细线边框"><span>表格细线边框</span></a></h4><p>可以直接更改表格标签的属性,但表格标签只包括外边框,因此若想要改变内边框需要设置单元格td的边框属性</p><p>默认情况下单元格紧凑排列,中间没有间距,而两个单元格的边框并在一起所以会看着内边框比外边框粗</p><p>可以使用: border-collapse属性控制浏览器绘制表格边框的方式。它控制相邻单元格的边框。</p><p>collapse单词是合并的意思 相邻边框合并在一起</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>border-collapse:collapse;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>边框会额外增加盒子的实际大小。因此我们有两种方案解决：</p><ol><li>测量盒子大小的时候，不量边框</li><li>如果测量的时候包含了边框，则需要width/height减去边框宽度 边框有分左右因此减时减双倍</li></ol><h3 id="内边距" tabindex="-1"><a class="header-anchor" href="#内边距"><span>内边距</span></a></h3><p>padding属性用于设置内边距，即边框与内容之间的距离。 内边距会影响盒子大小 如果盒子不指定盒子的高度和宽度,那么内边距就不会影响盒子的大小</p><table><thead><tr><th>属性</th><th>作用</th></tr></thead><tbody><tr><td>padding-left</td><td>左内边距</td></tr><tr><td>padding-right</td><td>右内边距</td></tr><tr><td>padding-top</td><td>上内边距</td></tr><tr><td>padding-bottom</td><td>下内边距</td></tr></tbody></table><p>1个值，代表上下左右都有指定像素内边距； 2个值，代表上下内边距是第一个值的像素,左右内边距是第二个值的像素； 3个值，代表上内边距第一个值,左右内边距第二个值,下内边距第三个值； 4个值，上右下左 顺时针</p><h3 id="外边距" tabindex="-1"><a class="header-anchor" href="#外边距"><span>外边距</span></a></h3><p>margin用于设计外边距,即盒子与盒子之间的距离 margin-left左外边距,其他相同</p><h4 id="盒子水平居中" tabindex="-1"><a class="header-anchor" href="#盒子水平居中"><span>盒子水平居中</span></a></h4><p>让ehzi水平居中必须指定了宽度且盒子的左右外边距都设置为auto</p><p>让行内元素或行内块元素水平居中可以给它的父亲添加<code>text-align:center</code></p><p><strong>嵌套块元素垂直外边距的塌陷</strong> 对于两个嵌套关系（父子关系）的块元素，父元素有上外边距同时子元素也有上外边距，此时父元素会塌陷较大的外边距值。</p><p>解决方案：</p><ol><li>可以为父元素定义上边框</li><li>可以为父元素定义上内边距</li><li>可以为父元素添加overflow:hidden。</li></ol><p>网页元素很多都带有默认的内外边距，而且不同浏览器默认的也不一致。因此我们在布局前，首先要清除下网页元素的内外边距。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>*{</span></span>
<span class="line"><span>	padding:0;    //清除内边距</span></span>
<span class="line"><span>	margin:0;    //清除外边距</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="圆角边框" tabindex="-1"><a class="header-anchor" href="#圆角边框"><span>圆角边框</span></a></h3><p>radius半径（圆的半径)原理：(椭)圆与边框的交集形成圆角效果</p><p>设置的是切角圆形的半径 <code>border-radius</code>属性用于设置元素的外边框圆角</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>border-radius:10px;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>也可以使用百分比,百分比表示的是切角圆半径与边框宽高的比例,如50%就是半径为边框宽高的一半</p><p>也可以对四个角单独设置,如果简写的话就是从左上角开始顺时针方向取值 分开写：border-top-left-radius、border-top-right-radius、border-bottom-right-radius和border-bottom-left-radiusR</p><h3 id="盒子阴影" tabindex="-1"><a class="header-anchor" href="#盒子阴影"><span>盒子阴影</span></a></h3><p>使用<code>box-shadow</code>属性为盒子添加阴影。</p><table><thead><tr><th>值</th><th>描述</th></tr></thead><tbody><tr><td>h-shadow</td><td>必需。水平阴影的位置。允许负值。</td></tr><tr><td>v-shadow</td><td>必需。垂直阴影的位置。允许负值。</td></tr><tr><td>blur</td><td>可选。模糊距离。</td></tr><tr><td>spread</td><td>可选。阴影的尺寸。</td></tr><tr><td>color</td><td>可选。阴影的颜色。请参阅CSS颜色值。</td></tr><tr><td>inset</td><td>可选。将外部阴影(outset)改为内部阴影。默认是outset,但是不能写outset要修改只能写inset</td></tr></tbody></table><h3 id="文字阴影" tabindex="-1"><a class="header-anchor" href="#文字阴影"><span>文字阴影</span></a></h3><p>使用t<code>ext-shadow</code>属性将阴影应用于文本。 与盒子阴影不同,文字阴影只有四个值:</p><ol><li>h-shadow</li><li>v-shadow</li><li>blur</li><li>color</li></ol>`,40)]))}const h=e(s,[["render",r]]),p=JSON.parse('{"path":"/front/css/4/","title":"4 盒子模型","lang":"zh-CN","frontmatter":{"title":"4 盒子模型","createTime":"2025/06/18 21:05:52","permalink":"/front/css/4/"},"readingTime":{"minutes":3.72,"words":1115},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/4 盒子模型.md","headers":[]}');export{h as comp,p as data};
